export default{getItem(name){let s=sessionStorage.getItem(name);if(!s)return{};try{s=JSON.parse(s)}catch(e){return{}}return s},setItem(name,values,force=!1){if("string"!=typeof name)return console.error('Parameter "name" musi byt string! \nname: ',name);force&&this.removeItem(name);if(!values){sessionStorage.setItem(name,values);return}let a;if("object"==typeof values)if(values instanceof Array){a=sessionStorage[name]?this.getItem(name):[];a.push(...values);sessionStorage.setItem(name,JSON.stringify(a))}else{a=sessionStorage[name]?this.getItem(name):{};Object.assign(a||{},values);sessionStorage.setItem(name,JSON.stringify(a))}else sessionStorage.setItem(name,values)},deleteItem(name,key){let a=this.getItem(name);delete a[key];console.log("a: ",a);sessionStorage.setItem(name,JSON.stringify(a))},removeItem(name){sessionStorage.removeItem(name)}};